INSERT INTO vault_modules (
  user_id, title, slug, description, domain, module_type, language, tags, code,
  why_it_matters, usage_hint, code_example, source_project, validation_status,
  visibility, difficulty, estimated_minutes, module_group, implementation_order,
  related_modules, solves_problems, common_errors, test_code, context_markdown,
  ai_metadata
) VALUES (
  '82f6649d-f8d6-4da3-9704-d69b2f37d1a1',
  'Token Manager Architecture Guide — FSM-Based Auth Token Lifecycle System',
  'token-manager-architecture-guide',
  'Architecture guide explaining how the 8 components of the Token Manager system (FSM, Service, UnifiedService, Heartbeat, CrossTabLock, Persistence, Types, barrel) integrate into a complete auth token lifecycle management architecture.',
  'architecture',
  'architecture_doc',
  'typescript',
  ARRAY['token-manager','architecture-guide','fsm','finite-state-machine','auth','token-lifecycle','cross-tab','heartbeat','persistence','state-machine'],
  E'/**\n * Token Manager Architecture Guide\n *\n * SYSTEM OVERVIEW:\n * The Token Manager is a FSM-based system managing the complete lifecycle\n * of authentication tokens. Impossible states cannot exist through explicit\n * state transitions and discriminated unions.\n *\n * COMPONENT MAP (8 files):\n *\n * Token Manager System (index.ts — Barrel exports)\n *   ├── Types (types.ts) — TokenState(6), TokenEvent(9), TokenContext, TOKEN_TIMING\n *   ├── Machine (machine.ts) — transition(state, event) → nextState | null\n *   ├── Service (service.ts) — FSM wrapper with side effects, heartbeat, subscribers\n *   ├── UnifiedService (unified-service.ts) — Singleton facade: isAuthenticated(), refreshToken(), etc.\n *   ├── Persistence (persistence.ts) — localStorage adapter for auth STATE (not tokens)\n *   ├── Heartbeat (heartbeat.ts) — Periodic expiry checker, emits TIMER_NEAR_EXPIRY/EXPIRED\n *   ├── CrossTabLock (cross-tab-lock.ts) — BroadcastChannel + localStorage fallback\n *   └── Barrel (index.ts) — Public API surface\n *\n * STATE MACHINE (6 states, 9 events):\n *\n *   idle ──LOGIN_SUCCESS──▶ authenticated\n *                               │\n *                    TIMER_NEAR_EXPIRY\n *                               ▼\n *                           expiring ──REFRESH_START──▶ refreshing\n *                                                        │       │\n *                                              REFRESH_SUCCESS  REFRESH_FAILED\n *                                                   │              │\n *                                            authenticated    expired/error\n *\n *   Any state ──LOGOUT/CLEAR──▶ idle\n *\n * KEY DECISIONS:\n * 1. NO XState dependency — Pure TypeScript FSM with transition table\n * 2. Tokens in httpOnly cookies — Only AUTH STATE in localStorage\n * 3. Heartbeat as fallback — Primary monitoring via SessionCommander\n * 4. UnifiedService as facade — Single entry point for all auth ops\n */\n\nimport { isAuthenticated, refreshToken, clearAuth, setAuthenticated, subscribeToAuth } from ''@/lib/token-manager'';\n\n// Check auth (synchronous)\nif (isAuthenticated()) { /* valid session */ }\n\n// Subscribe to state changes\nconst unsub = subscribeToAuth((state, ctx) => {\n  console.log(''Auth:'', state, ''Expires:'', ctx.expiresAt);\n});\n\n// After login\nsetAuthenticated(14400); // 4h in seconds\n\n// Logout\nclearAuth();',
  'Without a formal state machine, auth state devolves into tangled boolean flags (isLoggedIn, isRefreshing, hasError, isExpired) creating impossible combinations and race conditions. The FSM makes illegal states unrepresentable: you cannot be simultaneously refreshing and idle, or authenticated with null expiresAt. The transition table serves as living documentation — every possible state change is visible in one function.',
  'Use when building any SaaS with robust token lifecycle management. Pairs with session-commander-architecture-guide — Token Manager owns STATE, Session Commander owns COORDINATION.',
  E'// FSM transition (core pattern):\nimport { transition, INITIAL_STATE, INITIAL_CONTEXT } from ''@/lib/token-manager/machine'';\n\nlet state = INITIAL_STATE; // idle\nlet context = INITIAL_CONTEXT;\n\nconst r1 = transition(state, { type: ''LOGIN_SUCCESS'', expiresIn: 14400 }, context);\nif (r1) {\n  state = r1.nextState;     // authenticated\n  context = r1.nextContext; // { expiresAt: Date.now() + 14400000, ... }\n}\n\n// State predicates:\nimport { canMakeApiCalls } from ''@/lib/token-manager/machine'';\nconsole.log(canMakeApiCalls(''authenticated'')); // true\nconsole.log(canMakeApiCalls(''expired''));        // false',
  'risecheckout',
  'validated',
  'global',
  'advanced',
  180,
  'token-manager',
  0,
  ARRAY['0d687429-0f6c-4c74-a46f-26b3f36fa1dd','be66ea5d-fc3b-4a3c-86fe-bf889719de65','aab502c7-22a2-4d44-8b96-2d01cf5e8a67','4c02c917-bc31-4040-9350-963ea9d73f45']::uuid[],
  ARRAY['boolean flag spaghetti for auth state','impossible auth states (refreshing + idle)','race conditions in token refresh','how to implement FSM without XState','token lifecycle management architecture','where to store auth state vs tokens'],
  '[{"error":"transition() returns null","cause":"Invalid state+event combination — FSM rejected illegal transition","fix":"Check transition table in machine.ts. Event is not valid for current state."},{"error":"Token appears expired immediately after login","cause":"expiresIn passed in milliseconds instead of seconds","fix":"LOGIN_SUCCESS expects expiresIn in SECONDS. FSM multiplies by 1000 internally."},{"error":"Auth state lost after page refresh","cause":"Persistence layer not restoring state on mount","fix":"Call restoreTokenState() in AuthProvider initialization before any auth checks"}]'::jsonb,
  E'import { transition, INITIAL_STATE, INITIAL_CONTEXT, canMakeApiCalls } from ''@/lib/token-manager/machine'';\n\nconst r1 = transition(''idle'', { type: ''LOGIN_SUCCESS'', expiresIn: 3600 }, INITIAL_CONTEXT);\nassert(r1 !== null, ''LOGIN_SUCCESS from idle should succeed'');\nassert(r1.nextState === ''authenticated'');\nassert(r1.nextContext.expiresAt !== null);\n\nconst r2 = transition(''idle'', { type: ''REFRESH_START'' }, INITIAL_CONTEXT);\nassert(r2 === null, ''REFRESH_START from idle should be rejected'');\n\nassert(canMakeApiCalls(''authenticated'') === true);\nassert(canMakeApiCalls(''expired'') === false);',
  E'## Overview\n\nThe Token Manager is a FSM-based architecture for managing authentication token lifecycles in SaaS applications. Replaces ad-hoc boolean flag management with deterministic, type-safe state machine.\n\n## How it Works\n\n8 files in layered architecture:\n1. **Types** — Discriminated unions for TokenState (6 states), TokenEvent (9 events), TokenContext, timing constants.\n2. **Machine** — Pure transition function: (state, event, context) → {nextState, nextContext} | null. Plus predicates: canMakeApiCalls, needsRefresh, isExpired.\n3. **Service** — FSM wrapper with side effects: persistence, heartbeat, subscriber notification.\n4. **UnifiedService** — Singleton facade: isAuthenticated(), refreshToken(), clearAuth(), setAuthenticated(), subscribeToAuth().\n5. **Persistence** — localStorage adapter for auth STATE (not tokens). Tokens in httpOnly cookies.\n6. **Heartbeat** — Periodic timer checking token expiry, emitting FSM events.\n7. **CrossTabLock** — BroadcastChannel + localStorage fallback preventing concurrent refresh.\n8. **Barrel** — Public API surface with selective re-exports.\n\n## When to Use\n- SaaS with JWT/cookie auth and expiring tokens\n- When deterministic auth state management is needed\n- Multi-tab applications\n\n## When NOT to Use\n- Simple session-only auth (no refresh tokens)\n- SSR apps where auth is server-managed\n- Apps using third-party auth SDKs (Auth0, Firebase Auth)\n\n## Performance\n- FSM transition is O(1) — pure switch/case\n- Heartbeat interval: 60s (configurable)\n- Persistence writes debounced via Service layer\n- CrossTabLock: BroadcastChannel (zero-copy) with localStorage polling fallback',
  '{"npm_dependencies":[],"env_vars_required":[],"ai_rules":["NEVER store actual tokens in localStorage — only auth STATE","transition() is PURE — no side effects. Side effects belong in Service layer","Always pair with Session Commander for production use"]}'::jsonb
);